// Board Pack: build the Anthropic Messages request from the app-computed figure set.
// The app sends ONLY the figures; this node turns them into a trace-to-data prompt.
const NL = String.fromCharCode(10);
const inp = $input.first().json;
const b = inp.body || inp;
const fs = (b && b.figureSet) || {};
const M = fs.metrics || [];
const L = fs.levers || [];
const T = fs.traceTable || [];
const meta = fs.meta || {};
const order = (meta.metricOrder || M.map(function (m) { return m.label; })).join(' -> ');

const mLines = M.map(function (m) {
  return m.order + '. ' + m.label + ': ' + m.valueDisplay +
    ' (target ' + m.targetDisplay + ', PROVISIONAL; status ' + m.status +
    (m.note ? '; ' + m.note : '') + ')';
}).join(NL);

const lLines = L.length
  ? L.map(function (l, i) {
      return (i + 1) + '. ' + l.title + ' - gap ' + l.gapDisplay +
        '; estimated pipeline impact ' + l.impactDisplay + ' (' + l.basis + ')';
    }).join(NL)
  : '(no open gaps in this scope)';

const allowed = T.map(function (t) { return '- ' + t.label + ': ' + t.display; }).join(NL);

const system = [
  'You write the executive board pack for CWSI, a B2B cybersecurity firm, from its marketing-intelligence dashboard.',
  'TRACE-TO-DATA RULES (absolute, non-negotiable):',
  '1) Use ONLY numbers that appear in FIGURES or ALLOWED NUMBERS below. Never invent, estimate, extrapolate, round to a new value, or calculate a new number. If a figure you want is not supplied, describe it qualitatively with no number.',
  '2) Quote every number in its exact displayed form (for example "GBP 612k" as shown, "17.5%").',
  '3) Targets are PROVISIONAL placeholders - say a target is provisional whenever you cite one. If a metric actual is pending, say it is pending; never fabricate it.',
  '4) Follow the agreed metric order: ' + order + '.',
  'Audience: the board and the CCO. Be concise, direct and decision-oriented. Return JSON only, matching the required schema.'
].join(NL);

const user = [
  'Scope: ' + (meta.regionLabel || 'All Regions') + ' | ' + (meta.quarterLabel || 'YTD') + ' | FY2026.',
  '',
  'FIGURES (metric: actual (target; status)):',
  mLines,
  '',
  'GAPS TO CLOSE (ranked by estimated pipeline impact):',
  lLines,
  '',
  'ALLOWED NUMBERS (the only numbers you may state, with their exact display form):',
  allowed,
  '',
  'Produce:',
  '- narrative.onTrack: what is on or above (provisional) target, in the agreed metric order.',
  '- narrative.behindAddressable: what is behind but addressable, citing the ranked levers and their estimated pipeline impact.',
  '- narrative.h2Plan: the H2 plan to close the gaps, highest-impact levers first.',
  '- recommendations[]: prioritised actions; each {title, rationale, estimatedImpact (use a lever impact figure where applicable, else "target pending"), metric (the board metric it moves)}.'
].join(NL);

const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    narrative: {
      type: 'object',
      additionalProperties: false,
      properties: {
        onTrack: { type: 'string' },
        behindAddressable: { type: 'string' },
        h2Plan: { type: 'string' }
      },
      required: ['onTrack', 'behindAddressable', 'h2Plan']
    },
    recommendations: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          title: { type: 'string' },
          rationale: { type: 'string' },
          estimatedImpact: { type: 'string' },
          metric: { type: 'string' }
        },
        required: ['title', 'rationale', 'estimatedImpact', 'metric']
      }
    }
  },
  required: ['narrative', 'recommendations']
};

return [{ json: { anthropicBody: {
  model: 'claude-opus-4-8',
  max_tokens: 8000,
  thinking: { type: 'adaptive' },
  system: system,
  messages: [{ role: 'user', content: user }],
  output_config: { format: { type: 'json_schema', schema: schema } }
} } }];

// Parse the Anthropic response. With adaptive thinking the content array may hold
// a thinking block before the text block, so pick the text block explicitly.
const res = $input.first().json;
const content = res.content || [];
let text = '';
for (const blk of content) { if (blk.type === 'text') { text = blk.text; break; } }
let parsed = {};
try { parsed = JSON.parse(text); } catch (e) { parsed = { _parseError: String(e), raw: text }; }
return [{ json: {
  narrative: parsed.narrative || {},
  recommendations: Array.isArray(parsed.recommendations) ? parsed.recommendations : [],
  model: res.model || 'claude-opus-4-8'
} }];
